// Spiral Fidget Cone — print-in-place: a cone split into two interleaved spiral
// ribbons that twist apart. componentCount === 2. Treat 1 unit ≈ 1 mm.
const { Manifold, CrossSection } = api;
const p = api.params({
  baseR:     { type: 'number', default: 15, min: 9,  max: 24, step: 0.5, unit: 'mm', label: 'Base radius' },
  height:    { type: 'number', default: 50, min: 28, max: 80, step: 1,   unit: 'mm', label: 'Height' },
  turns:     { type: 'number', default: 5,  min: 2,  max: 8,  step: 0.5, label: 'Spiral turns' },
  flutes:    { type: 'number', default: 22, min: 0,  max: 40, step: 1,   label: 'Surface flutes' },
  clearance: { type: 'number', default: 0.8, min: 0.4, max: 1.6, step: 0.1, unit: 'mm', label: 'Print clearance' },
});
const H = p.height, taper = 0.12;
const fluted = (r, lobes, ampFrac) => {
  if (lobes <= 0) return CrossSection.circle(r, 160);
  const amp = r * ampFrac, steps = 150, pts = [];
  for (let i = 0; i < steps; i++) {
    const a = (i / steps) * Math.PI * 2;
    const rr = r - amp * (0.5 + 0.5 * Math.cos(lobes * a));
    pts.push([Math.cos(a) * rr, Math.sin(a) * rr]);
  }
  return CrossSection.ofPolygons([pts]);
};
// Fluted cone body with a gentle counter-swirl, capped by a rounded finial tip.
const body = fluted(p.baseR, p.flutes, 0.05).extrude(H, 200, 360 * 0.4, taper)
  .add(Manifold.sphere(p.baseR * 0.13, 20).translate([0, 0, H]));
// Full-diameter helical slab (thickness = clearance) splits it into 2 ribbons.
const cut = CrossSection.square([p.clearance, p.baseR * 5], true)
  .extrude(H + 8, 440, 360 * p.turns, 1).translate([0, 0, -4]);
const parts = body.subtract(cut).decompose();
const palette = ['#f5b324', '#7c3aed'];
return api.labeledUnion(parts.map((s, i) => ({ name: 'ribbon' + i, shape: s, color: palette[i % 2] })));
